# nimbus_detect_secrets
import json
import os
import re

pattern = re.compile(r'(^|/)(\.env(\.|$)|id_rsa|id_dsa|.*\.pem$|.*\.p12$|.*\.key$)', re.IGNORECASE)
allowed_env_templates = re.compile(r'(^|/)\.env\.(example|sample|template|dist|defaults)(\.|$)', re.IGNORECASE)
excluded_dirs = {'.git', 'node_modules', '.next', '.nuxt', '.svelte-kit', '.turbo', '.cache', 'dist', 'build', 'coverage', 'target'}
root = os.getcwd()
matches = []
for dirpath, dirnames, filenames in os.walk(root):
    rel_dir = os.path.relpath(dirpath, root)
    if rel_dir == '.':
        rel_dir = ''
    if rel_dir and any(part in excluded_dirs for part in rel_dir.split(os.sep)):
        continue
    dirnames[:] = [d for d in dirnames if d not in excluded_dirs]
    for name in filenames:
        absolute = os.path.join(dirpath, name)
        rel = os.path.relpath(absolute, root).replace('\\', '/')
        if allowed_env_templates.search(rel):
            continue
        if pattern.search(rel):
            matches.append(rel)
print(json.dumps(matches[:25]))
